const curatedResourceIdsForWellnessRow = (row: SampleReportRowSeed) => {
  const resourceIds = ["wellness-sample-pdf"];

  if (row.sourceLabel === "FDA") {
    resourceIds.push("fda-pgx-biomarkers-labeling", "cpic-g6pd-supplement", "fda-pgx-associations");
  }

  if (row.genes.includes("MTHFR")) {
    resourceIds.push("cdc-mthfr-folic-acid", "pharmgkb");
  }

  if (row.genes.includes("CYP2D6")) {
    resourceIds.push("pubmed-cyp2d6-antihistamines", "pharmgkb");
  }

  if (row.genes.some((gene) => ["ABCB1", "CYP3A5", "CYP4F2", "NAT2", "PAH", "NR1H3"].includes(gene))) {
    resourceIds.push("pharmgkb");
  }

  return [...new Set(resourceIds)];
};

const wellnessSampleRows: SampleReportRowSeed[] = wellnessBaseSampleRows.map((row) => {
  const sourceResourceIds = curatedResourceIdsForWellnessRow(row);
  const hasCuratedSupport = sourceResourceIds.length > 1;

  return {
    ...row,
    sourceResourceIds,
    sourceBindingStatus: "exact",
    sourceBindingNote: hasCuratedSupport
      ? "The public sample PDF provides the exact formal row and source label; additional resources are curated support, not proof of Sequencing.com's hidden original article citation."
      : "The public sample PDF provides the exact formal row and source label; no credible additional support source has been bound yet.",
  };
});

