export const seedReportPackages: ReportPackageSeed[] = [
  wellnessGeneticGuide,
  ...catalogSeedEntries
    .filter((entry) => entry.slug !== wellnessGeneticGuide.slug)
    .map(makeBacklogReport)
    .map(enhanceCatalogReport),
  ...unidentifiedAuthenticatedSlots.map(makeUnidentifiedAuthenticatedReport),
];
